from pymongo.errors import OperationFailure


class SafeMongoFilter:
    """A safe MongoDB filtering service that avoids server-side JavaScript execution."""

    # Whitelist of allowed MongoDB query operators
    ALLOWED_OPERATORS = {
        "$eq", "$ne", "$gt", "$gte", "$lt", "$lte",
        "$in", "$nin", "$exists", "$type",
        "$and", "$or", "$not", "$nor",
        "$regex", "$size", "$all", "$elemMatch",
        "$mod",
    }

    # Operators that must NEVER be allowed (server-side JS execution)
    BLOCKED_OPERATORS = {
        "$where",
        "$accumulator",
        "$function",
        "$expr",  # Can be safe but can also be abused; block by default
    }

    # Blocked patterns in string values that could indicate JS injection
    BLOCKED_PATTERNS = [
        re.compile(r"function\s*\(", re.IGNORECASE),
        re.compile(r"this\.", re.IGNORECASE),
        re.compile(r"sleep\s*\(", re.IGNORECASE),
        re.compile(r"db\.", re.IGNORECASE),
        re.compile(r"process\.", re.IGNORECASE),
        re.compile(r"require\s*\(", re.IGNORECASE),
        re.compile(r"eval\s*\(", re.IGNORECASE),
        re.compile(r"exec\s*\(", re.IGNORECASE),
    ]

    def __init__(self, connection_string="mongodb://localhost:27017/", database="mydb"):
        self.client = MongoClient(connection_string)
        self.db = self.client[database]

    def validate_filter(self, filter_dict):
        """
        Recursively validate a filter dictionary to ensure it does not contain
        any dangerous operators like $where that enable server-side JavaScript execution.
        
        Returns (is_valid, error_message)
        """
        if not isinstance(filter_dict, dict):
            return self._validate_value(filter_dict)

        for key, value in filter_dict.items():
            # Check if the key is a blocked operator
            if key in self.BLOCKED_OPERATORS:
                return False, (
                    f"Operator '{key}' is blocked. Server-side JavaScript execution "
                    f"is not allowed for security reasons."
                )

            # Check if the key looks like an unknown operator (starts with $)
            if key.startswith("$") and key not in self.ALLOWED_OPERATORS:
                return False, (
                    f"Operator '{key}' is not in the allowed operators list. "
                    f"Allowed operators: {sorted(self.ALLOWED_OPERATORS)}"
                )

            # Recursively validate the value
            if isinstance(value, dict):
                is_valid, error = self.validate_filter(value)
                if not is_valid:
                    return False, error
            elif isinstance(value, list):
                for item in value:
                    if isinstance(item, dict):
                        is_valid, error = self.validate_filter(item)
                        if not is_valid:
                            return False, error
                    else:
                        is_valid, error = self._validate_value(item)
                        if not is_valid:
                            return False, error
            elif isinstance(value, str):
                is_valid, error = self._validate_value(value)
                if not is_valid:
                    return False, error

        return True, None

    def _validate_value(self, value):
        """Validate a single value for dangerous patterns."""
        if isinstance(value, str):
            for pattern in self.BLOCKED_PATTERNS:
                if pattern.search(value):
                    return False, (
                        f"Value contains a blocked pattern that resembles "
                        f"JavaScript code: '{value}'"
                    )
        return True, None

    def build_safe_filter(self, user_filter):
        """
        Build a safe MongoDB filter from user input.
        Validates and sanitizes the filter to prevent JavaScript injection.
        
        Args:
            user_filter: A dictionary representing the MongoDB query filter.
            
        Returns:
            The validated filter dictionary.
            
        Raises:
            ValueError: If the filter contains dangerous operators or patterns.
        """
        if not isinstance(user_filter, dict):
            raise ValueError("Filter must be a dictionary.")

        is_valid, error = self.validate_filter(user_filter)
        if not is_valid:
            raise ValueError(f"Invalid filter: {error}")

        return user_filter

    def query(self, collection_name, user_filter, projection=None, limit=100):
        """
        Execute a safe query against MongoDB.
        
        Args:
            collection_name: Name of the collection to query.
            user_filter: User-provided filter dictionary (will be validated).
            projection: Optional projection dictionary.
            limit: Maximum number of documents to return.
            
        Returns:
            List of matching documents.
        """
        # Validate the filter
        safe_filter = self.build_safe_filter(user_filter)

        # Validate projection if provided
        if projection is not None:
            if not isinstance(projection, dict):
                raise ValueError("Projection must be a dictionary.")
            is_valid, error = self.validate_filter(projection)
            if not is_valid:
                raise ValueError(f"Invalid projection: {error}")

        collection = self.db[collection_name]

        try:
            cursor = collection.find(safe_filter, projection).limit(limit)
            return list(cursor)
        except OperationFailure as e:
            raise RuntimeError(f"MongoDB query failed: {e}")

    def close(self):
        """Close the MongoDB connection."""
        self.client.close()


